output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?duration WHERE {
  {
    ?game wdt:P1440 wd:Q334634 ; wdt:P1441 wd:Q650840
  } UNION {
    ?game wdt:P1440 wd:Q650840 ; wdt:P1441 wd:Q334634
  }
  ?game wdt:P1455 ?series .
  ?series wdt:P31 wd:Q1363275 .
  ?game wdt:P2090 ?duration .
}
ORDER BY ?duration
LIMIT 2
OFFSET 1

